public void validateFixture(final String[][] pairs) {
    if (pairs.length == 0) {
        fail("Test fixture is empty");
    }
    for (int i = 0; i < pairs.length; i++) {
        if (pairs[i].length != 2) {
            fail("Error in test fixture in the data array at index " + i);
        }
    }
}

